from collections import defaultdict, deque
import numpy as np
from datetime import datetime

class ToolUsageMonitor:
    def __init__(self, window_size: int = 500, z_score_threshold: float = 2.5):
        self.window_size = window_size
        self.z_score_threshold = z_score_threshold
        self.tool_call_history = deque(maxlen=window_size)
        self.baseline_profiles: dict[str, dict] = {}
        self.alerts: list[dict] = []

    def record_tool_calls(self, session_id: str, tools_called: list[str]):
        """Record tool calls for a single agent session."""
        profile = {
            'session_id': session_id,
            'tools': tools_called,
            'tool_count': len(tools_called),
            'unique_tools': len(set(tools_called)),
            'tool_sequence_hash': hash(tuple(tools_called)),
            'timestamp': datetime.utcnow().isoformat()
        }
        self.tool_call_history.append(profile)
        return profile

    def establish_tool_baseline(self):
        """Compute baseline statistics from current history."""
        if len(self.tool_call_history) < 50:
            raise ValueError("Need at least 50 sessions to establish baseline.")

        counts = [p['tool_count'] for p in self.tool_call_history]
        tool_freq = defaultdict(int)
        for p in self.tool_call_history:
            for tool in p['tools']:
                tool_freq[tool] += 1

        total_sessions = len(self.tool_call_history)
        self.baseline_profiles = {
            'mean_tool_count': np.mean(counts),
            'std_tool_count': np.std(counts),
            'tool_frequencies': {
                tool: count / total_sessions
                for tool, count in tool_freq.items()
            },
            'established_at': datetime.utcnow().isoformat(),
            'sample_size': total_sessions
        }
        print(f"Tool baseline established from {total_sessions} sessions.")
        print(f"Mean tools per session: {self.baseline_profiles['mean_tool_count']:.2f}")
        return self.baseline_profiles

    def check_session_for_drift(self, tools_called: list[str]) -> dict:
        """Check if a session's tool usage deviates from baseline."""
        if not self.baseline_profiles:
            raise ValueError("Baseline not established.")

        anomalies = []
        tool_count = len(tools_called)

        # Check tool count z-score
        z_score = abs(
            (tool_count - self.baseline_profiles['mean_tool_count']) /
            (self.baseline_profiles['std_tool_count'] + 1e-8)
        )
        if z_score > self.z_score_threshold:
            anomalies.append({
                'type': 'tool_count_anomaly',
                'observed': tool_count,
                'expected_mean': self.baseline_profiles['mean_tool_count'],
                'z_score': round(z_score, 2)
            })

        # Check for unexpected tools
        known_tools = set(self.baseline_profiles['tool_frequencies'].keys())
        for tool in tools_called:
            if tool not in known_tools:
                anomalies.append({
                    'type': 'unknown_tool',
                    'tool': tool,
                    'message': f"Tool '{tool}' not seen in baseline"
                })

        # Check for missing high-frequency tools
        for tool, freq in self.baseline_profiles['tool_frequencies'].items():
            if freq > 0.7 and tool not in tools_called:  # Expected in 70%+ of sessions
                anomalies.append({
                    'type': 'missing_expected_tool',
                    'tool': tool,
                    'baseline_frequency': freq
                })

        result = {
            'drift_detected': len(anomalies) > 0,
            'anomaly_count': len(anomalies),
            'anomalies': anomalies,
            'tools_called': tools_called,
            'timestamp': datetime.utcnow().isoformat()
        }

        if result['drift_detected']:
            self.alerts.append(result)
            print(f"[TOOL DRIFT] {len(anomalies)} anomalies detected: {anomalies}")

        return result


# Usage
monitor = ToolUsageMonitor(window_size=500, z_score_threshold=2.5)

# Simulate baseline recording
for i in range(100):
    monitor.record_tool_calls(
        session_id=f'session_{i}',
        tools_called=['search_web', 'read_document', 'summarize']
    )

monitor.establish_tool_baseline()

# Check a suspicious session
result = monitor.check_session_for_drift(
    tools_called=['search_web', 'execute_code', 'write_file',
                  'send_email', 'delete_record']  # Unusual tool pattern
)
print(f"Drift detected: {result['drift_detected']}")
print(f"Anomalies: {result['anomalies']}")
